function sendEmail() {
    const {
        apiKey, fromAddress, toAddress, subject, textBody
    } = config; // pull keys out of config file or Azure functions KeyVault
    // https://github.com/sendgrid/sendgrid-nodejs#example
    return SendGrid(apiKey).request(emailData => {
       emailData.method = 'POST' 
       emailData.path = '/v3/mail/send'
       emailData.body = {
         "personalizations": [
            {
              "to": [{
                "email": toAddress,
              }],
              "subject": subject
            }
          ],
          "from": {
            "email": fromAddress
          },
          "content": [
            {
              "type": "text/plain",
              "value": textBody
            }
          ]
        }
    }).then(response => {
      if (response.statusCode < 200 || response.statusCode > 299) 
        throw new Error('Bad Request: ' + JSON.stringify(response))
        return response;
    });
}

function sendSMS() {
    const {sid, token, phone} = config // pull keys out of config file or Azure functions KeyVault
    // https://www.twilio.com/docs/sms/api-send-quickstart
    const client = Twilio(sid, token);
        return client.messages.create({
            to: phone, from: '+15703862498', body: "Hello world"
        }).then(message => {
            if (message.status !== 'queued')
                throw new Error('Bad Request for ' + message.to)
            return message;
        });
}